create table woods
(
    id            char(20) not null comment 'ID'
        primary key,
    woods_name    char(20) not null comment '林地名称',
    woods_number  char(20) not null comment '林地编号',
    woods_geojson text     not null comment '林地geojson',
    is_delete     int      not null comment '逻辑删除',
    create_time   datetime not null comment '创建时间',
    create_user   char(20) not null comment '创建人',
    update_time   datetime not null comment '修改时间',
    update_user   char(20) not null comment '修改人',
    constraint woods_name
        unique (woods_name),
    constraint woods_number
        unique (woods_number)
)
    comment '林地';

